import { useAuth } from "../context/AuthContext";

const DashboardPage = () => {
  const { user } = useAuth();

  return (
    <section className="card">
      <div className="page-header">
        <h2>Dashboard</h2>
        <p className="muted">
          Welcome back{user?.username ? `, ${user.username}` : ""}.
        </p>
      </div>
      <div>
        <p>
          Use the navigation above to manage students, instructors, courses, and
          enrollments.
        </p>
      </div>
    </section>
  );
};

export default DashboardPage;
